const b = $json.body || {};

// 1. Identify ALL Selected Sectors (e.g., sectors[0], sectors[1], etc.)
const selectedSectors = Object.keys(b)
  .filter(k => k.startsWith("sectors["))
  .map(k => b[k])
  .filter(Boolean); // Keep only non-empty values

// 2. Full mapping of Sectors to their website groups
const sectorMap = {
  "Healthcare": "website_for_healthcare",
  "Food & Catering": "website_for_food_and_catering",
  "Retail": "website_for_retail",
  "Manufacturing": "website_for_manufacturing",
  "Logistics": "website_for_logistics",
  "Facilities Management": "website_for_facilities_management"
};

let allTargetDomains = [];

// 3. Loop through every selected sector and gather their respective websites
selectedSectors.forEach(sector => {
  const groupPrefix = sectorMap[sector];
  if (groupPrefix) {
    const sectorWebsites = Object.keys(b)
      .filter(key => key.startsWith(`${groupPrefix}[`))
      .map(key => b[key])
      .filter(Boolean);

    allTargetDomains.push(...sectorWebsites);
  }
});

// 4. Date Formatting (DD/MM/YYYY -> YYYY-MM-DD)
let formattedDate = "";
if (b.date && b.date.includes('/')) {
  const [d, m, y] = b.date.split('/');
  formattedDate = `${y}-${m}-${d}`;
}

return [{
  json: {
    user: { 
      name: b.name, 
      email: b.email_address, 
      company: b.company_name 
    },
    research: { 
      topic: b.what_would_you_like_us_to_research,
      published_after: formattedDate 
    },
    selected_sectors: selectedSectors, // Now shows all selected sectors
    domains: [...new Set(allTargetDomains)] // De-duped list of all websites
  }
}];

let allResults = [];

// 1. Flatten all results from all domains into one list
for (const item of $input.all()) {
  if (item.json.results && item.json.results.length > 0) {
    allResults.push(...item.json.results);
  }
}

// 2. Sort by Tavily's AI Relevance Score (Descending)
allResults.sort((a, b) => b.score - a.score);

// 3. Keep only the Top 6 articles globally to ensure quality and save tokens
// We also filter out any results with very low scores (e.g., < 0.3)
const topResults = allResults
  .filter(r => r.score > 0.1) // Adjust this threshold if needed
  .slice(0, 6);

return topResults.map(r => ({ json: r }));

// Map both raw_content for the research AND the specific URLs for citations
const results = $input.all().map(item => {
  return {
    content: item.json.combined_research, // This is your raw_content
    source_info: `TITLE: ${item.json.title} | URL: ${item.json.url}`
  };
});

const joinedText = results.map(r => r.content).join('\n\n--- NEXT SOURCE ---\n\n');
const joinedSources = results.map(r => r.source_info).join('\n');

return {
  combined_text: joinedText,
  source_list: joinedSources,
  original_topic: $node["Normalize & Route"].json.research.topic
};
